const Render = {
    init() {
        EventBus.clear();
        this.gridCSS(); this.header(); this.horizon();

        BusWrap('structureChanged', () => this.hardRebuild());
        BusWrap('settingsChanged', () => { applySettings(); this.header(); this.horizonData(); });
        BusWrap('horizonToggled', () => {
            const btn = document.querySelector('[data-action="toggleHorizon"]');
            if(btn) btn.classList.toggle('active', state.settings.showHorizon);
            DOM.horizon.classList.toggle('is-expanded', state.settings.showHorizon);
            if(state.settings.showHorizon) { VirtualScroll.seekToDate(Utils.todayStr); this.horizonData(); }
            this.syncHorizonHeight();
            if (window.scrollY > DOM.header.offsetHeight) window.scrollBy(0, state.settings.showHorizon ? DOM.horizon.offsetHeight : -DOM.horizon.scrollHeight);
        });

        BusWrap('itemsChanged', (p) => { 
            if(p && p.dateStr) this.trackContent(p.dateStr); else dayMap.forEach((_, dStr) => this.trackContent(dStr)); 
            this.horizonData(); this.updateDayToggles(); this.updateProgress();
            if (uiState.isProjectsOpen) this.projectsDrawerUI();
        });
        BusWrap('itemsMoved', (p) => {
            if(p) { 
                if(p.oldDateStr) this.trackContent(p.oldDateStr); 
                if(p.newDateStr && p.oldDateStr !== p.newDateStr) this.trackContent(p.newDateStr); 
            }
            this.horizonData(); this.updateDayToggles(); this.updateProgress();
            if (uiState.isProjectsOpen) this.projectsDrawerUI();
        });
        BusWrap('itemToggled', (p) => {
            if(p && p.id) {
                const item = state.items.find(i => i.id === p.id);
                if(item) document.querySelectorAll(`.item[data-id="${p.id}"], .hz-item[data-id="${p.id}"]`).forEach(el => el.classList.toggle('is-done', item.isDone));
            }
            this.horizonData(); this.updateProgress();
            if (uiState.isProjectsOpen) this.projectsDrawerUI();
        });
        BusWrap('horizonChanged', () => this.horizonData());
        BusWrap('habitsChanged', () => this.habitStats());
        BusWrap('focusChanged', () => this.updateFocusDisplay());

        BusWrap('notesChanged', () => { if(uiState.isNotesOpen) this.notesDrawerUI(); });
        BusWrap('notesTabsChanged', () => { if(uiState.isNotesOpen) this.notesDrawerTabsOnly(); });

        BusWrap('projectsChanged', () => { if(uiState.isProjectsOpen) this.projectsDrawerUI(); });
        BusWrap('projectsTabsChanged', () => { if(uiState.isProjectsOpen) this.projectsDrawerTabsOnly(); });

        setInterval(() => { this.updateFocusDisplay(true); }, 60000);
    },

    hardRebuild() {
        const activeId = document.activeElement?.dataset?.id;
        DOM.body.innerHTML = ''; dayMap.clear();
        this.gridCSS(); this.header(activeId ? `[data-id="${activeId}"]` : null); this.horizon();
        VirtualScroll.seekToDate(Utils.todayStr);
    },

    snapItemHeight(itemEl) {
        if(!itemEl.classList.contains('is-expanded')) { itemEl.style.height = ''; return; }
        itemEl.style.height = 'auto'; 
        const rect = itemEl.getBoundingClientRect();
        const gridSize = 44;
        const snapped = Math.ceil(rect.height / gridSize) * gridSize;
        itemEl.style.height = snapped + 'px';
    },

    gridCSS() {
        let gridTemplate = '';

        if (uiState.isProjectsOpen) {
            const laneStr = state.lanes.map(sl => sl.id === uiState.activeLaneProjects ? 'minmax(200px, 1fr)' : 'var(--grid-size)').join(' ');
            gridTemplate = `var(--left-margin) ${laneStr}`;
        } else {
            const laneWidth = state.lanes.length > 3 ? 'minmax(220px, 1fr)' : 'minmax(140px, 1fr)';
            const laneStr = state.lanes.map(sl => sl.minimized ? 'var(--grid-size)' : laneWidth).join(' ');

            const focusStr = `var(--grid-size)`;

            let habitStr = '';
            if (state.settings.habitsMin) {
                habitStr = `var(--grid-size)`; 
            } else {
                habitStr = `repeat(${state.habits.length}, var(--grid-size)) var(--grid-size)`;
            }

            let diaryStr = state.settings.diaryMin ? 'var(--grid-size)' : `minmax(200px, 1.5fr)`;

            gridTemplate = `var(--left-margin) ${laneStr} var(--grid-size) ${focusStr} ${habitStr} ${diaryStr}`;
        }

        let css = `.grid-row { grid-template-columns: ${gridTemplate}; } #horizon-span-filler { grid-column: auto / -1; }`;
        state.lanes.forEach((l, i) => { css += `.sl-${l.id} { --lc: ${l.color || Config.PAL[i % Config.PAL.length]}; }`; });

        let styleTag = document.getElementById('dynamic-grid-style');
        if(!styleTag) { styleTag = document.createElement('style'); styleTag.id = 'dynamic-grid-style'; document.head.appendChild(styleTag); }
        styleTag.innerHTML = css;
    },

    header(activeFocusSelector = null) {
