                            </div>
                        </div>
                        <div class="tray-section"><span class="tray-label">Paper Style</span>
                            <div class="tray-toggle-group">
                                <div class="tray-toggle-btn action-btn ${state.settings.theme==='dotted'?'active':''}" role="button" tabindex="0" data-action="setTheme" data-val="dotted">Dotted</div>
                                <div class="tray-toggle-btn action-btn ${state.settings.theme==='lined'?'active':''}" role="button" tabindex="0" data-action="setTheme" data-val="lined">Lined</div>
                            </div>
                        </div>
                        <div class="tray-section"><span class="tray-label">Horizon Filter</span>
                            <div class="tray-toggle-group">
                                <div class="tray-toggle-btn action-btn ${state.settings.horizonMode==='all'?'active':''}" role="button" tabindex="0" data-action="setHzMode" data-val="all">All</div>
                                <div class="tray-toggle-btn action-btn ${state.settings.horizonMode==='scroll'?'active':''}" role="button" tabindex="0" data-action="setHzMode" data-val="scroll">Scrolled</div>
                            </div>
                        </div>
                        <div class="tray-section"><span class="tray-label">Data Backup</span>
                            <div class="tray-toggle-group">
                                <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="exportData">Export</div>
                                <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="importData">Import</div>
                            </div>
                        </div>
                        <div class="tray-section"><span class="tray-label">Help</span>
                            <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="showOnboarding">Tutorial</div>
                        </div>
                    </div>
                </div>
                <div class="ui-btn action-btn ${state.settings.showHorizon?'active':''}" role="button" tabindex="0" data-action="toggleHorizon" title="Horizon View">Hz</div>
                <div class="ui-btn action-btn ${uiState.isProjectsOpen?'active':''}" role="button" tabindex="0" data-action="toggleProjectsGlobal" title="Projects View">Prj</div>
                <div class="ui-btn action-btn" role="button" tabindex="0" data-action="scrollToToday" title="Jump to Today">Tod</div>
            </div>
        `;

        state.lanes.forEach(lane => {
            const isMin = uiState.isProjectsOpen ? (lane.id !== uiState.activeLaneProjects) : lane.minimized;
            html += `
                <div class="header-track sl-${lane.id} ${isMin ? 'is-minimized' : ''}">
                    <div class="track-controls">
                        <div class="ctrl-btn cdot action-btn" style="background:${lane.color}" role="button" tabindex="0" data-action="cycleColor" data-id="${lane.id}" title="Color"></div>
                        <div class="ctrl-btn action-btn" role="button" tabindex="0" data-action="minLane" data-id="${lane.id}" title="Minimize">-</div>
                        <div class="ctrl-btn action-btn" role="button" tabindex="0" data-action="openProjects" data-id="${lane.id}" title="Lane Projects">📁</div>
                        <div class="ctrl-btn action-btn" role="button" tabindex="0" data-action="openNotes" data-id="${lane.id}" title="Lane Notes">📝</div>
                        <div class="ctrl-btn del action-btn" role="button" tabindex="0" data-action="delLane" data-id="${lane.id}" title="Delete">×</div>
                    </div>
                    <input class="track-title action-input" type="text" value="${Utils.escape(lane.title)}" data-action="editLaneTitle" data-id="${lane.id}">
                    <div class="restore-btn action-btn" role="button" tabindex="0" data-action="minLane" data-id="${lane.id}">${Utils.escape(lane.title)}</div>
                </div>
            `;
        });

        html += `<div class="add-col hide-in-proj-mode"><div class="add-btn action-btn" role="button" tabindex="0" data-action="addLane" title="Add Lane">+</div></div>`;

        html += `
            <div class="focus-header-col v-bound hide-in-proj-mode">
                <div class="focus-title">FOCUS</div>
            </div>
        `;

        if (state.settings.habitsMin) {
            html += `<div class="habit-header-col v-bound is-minimized-col action-btn hide-in-proj-mode" role="button" tabindex="0" data-action="toggleHabitsMin" title="Maximize Habits"><div class="min-placeholder-text">Habits +</div></div>`;
        } else {
            state.habits.forEach((habit, idx) => {
                const bound = idx === 0 ? 'v-bound' : ''; 
                html += `
                    <div class="habit-header-col hide-in-proj-mode ${bound}" title="Right-Click to delete habit">
                        ${idx === 0 ? `<div class="min-toggle-btn action-btn" role="button" tabindex="0" data-action="toggleHabitsMin" title="Minimize Habits">-</div>` : ''}
                        <div class="habit-header-input action-contenteditable" contenteditable="true" spellcheck="false" data-id="${habit.id}">${Utils.escape(habit.title)}</div>
                        <div class="habit-stat" id="stat-${habit.id}"></div>
                    </div>
                `;
            });
            html += `
                <div class="add-col add-col-habits hide-in-proj-mode">
                    <div class="add-btn action-btn" role="button" tabindex="0" data-action="addHabit" title="Add Habit">+</div>
                    <div class="st-toggle">
                        <div class="action-btn ${state.settings.habitMode==='streak'?'active':''}" role="button" tabindex="0" data-action="setHabMode" data-val="streak">S</div>
                        <div class="action-btn ${state.settings.habitMode==='total'?'active':''}" role="button" tabindex="0" data-action="setHabMode" data-val="total">T</div>
                    </div>
                </div>
            `;
        }

        if (state.settings.diaryMin) {
            html += `<div class="diary-header-col v-bound is-minimized-col action-btn hide-in-proj-mode" role="button" tabindex="0" data-action="toggleDiaryMin" title="Maximize Diary"><div class="min-placeholder-text">Diary +</div></div>`;
        } else {
            html += `
                <div class="diary-header-col hide-in-proj-mode v-bound">
                    <div class="min-toggle-btn action-btn" role="button" tabindex="0" data-action="toggleDiaryMin" title="Minimize Diary">-</div>
                    <div class="diary-title">Diary</div>
                </div>
            `;
        }

        DOM.header.innerHTML = html;
        if (!state.settings.habitsMin) this.habitStats();

        if (activeFocusSelector) { setTimeout(() => { const el = document.querySelector(activeFocusSelector); if(el) { el.focus(); try{ el.selectionStart = el.selectionEnd = el.value.length; }catch(e){} } }, 10); }
    },

    notesDrawerUI() {
        const lane = state.lanes.find(l => l.id === uiState.activeLaneNotes);
        DOM.notesLaneTitle.innerText = lane ? `${lane.title} Notes` : 'Notes';
        this.notesDrawerTabsOnly();
        const activeNote = state.notes.find(n => n.id === uiState.activeNoteId);
        if (activeNote) {
            DOM.noteEmptyState.style.display = 'none'; DOM.noteEditor.style.display = 'flex';
            DOM.noteTitleInput.value = activeNote.title; DOM.noteBodyInput.innerHTML = activeNote.content || '';
        } else { DOM.noteEmptyState.style.display = 'block'; DOM.noteEditor.style.display = 'none'; }
    },

    notesDrawerTabsOnly() {
        const laneNotes = state.notes.filter(n => n.laneId === uiState.activeLaneNotes);
        let tabsHtml = '';
        laneNotes.forEach(note => {
            const isActive = note.id === uiState.activeNoteId;
            tabsHtml += `
                <div class="drawer-tab action-btn ${isActive ? 'active' : ''}" role="button" tabindex="0" data-action="switchNote" data-id="${note.id}" title="${Utils.escape(note.title)}">
                    ${Utils.escape(note.title) || 'Untitled'}
                    <span class="del-tab-btn action-btn" role="button" tabindex="0" data-action="deleteNote" data-id="${note.id}" title="Delete Note">×</span>
                </div>
            `;
        });
        DOM.notesTabs.innerHTML = tabsHtml;

        if(DOM.notesTabs._sortable) DOM.notesTabs._sortable.destroy();
        DOM.notesTabs._sortable = new Sortable(DOM.notesTabs, {
            animation: 150,
            onEnd: () => {
                const domIds = Array.from(DOM.notesTabs.children).map(c => c.dataset.id).filter(Boolean);
                Actions.mutate(() => {
                    const activeNotes = [];
                    domIds.forEach(id => { const n = state.notes.find(x => x.id === id); if(n) activeNotes.push(n); });
                    const otherNotes = state.notes.filter(n => n.laneId !== uiState.activeLaneNotes);
                    state.notes = [...otherNotes, ...activeNotes]; 
                }, 'silentSave');
            }
        });
    },

    projectsDrawerUI() {
        const lane = state.lanes.find(l => l.id === uiState.activeLaneProjects);
        DOM.projectsLaneTitle.innerText = lane ? `${lane.title} Projects` : 'Projects';
        this.projectsDrawerTabsOnly();

        DOM.sortBtnCustom.classList.toggle('active', uiState.projSortMode === 'custom');
        DOM.sortBtnDate.classList.toggle('active', uiState.projSortMode === 'date');

        const activeProj = state.projects.find(p => p.id === uiState.activeProjectId);
        if (activeProj) {
            DOM.projectEmptyState.style.display = 'none'; DOM.projectEditor.style.display = 'flex';
            DOM.projectTitleInput.value = activeProj.title;

            let projItems = state.items.filter(i => i.projectId === activeProj.id);
            if (uiState.projSortMode === 'date') {
                projItems.sort((a, b) => {
                    if (!a.dateStr) return 1; if (!b.dateStr) return -1;
                    return a.dateStr.localeCompare(b.dateStr);
                });
            }

            DOM.projectTaskList.innerHTML = '';
            if (projItems.length === 0) {
                DOM.projectTaskList.innerHTML = `<div class="hz-item action-btn" role="button" tabindex="0" data-action="addProjectTaskFirst" style="justify-content: center; cursor: pointer; color: #94a3b8; font-style: italic;">+ Add First Task</div>`;
            } else {
                projItems.forEach(itemData => {
                    const itemEl = document.createElement('div');
                    itemEl.className = `item sl-${lane.id} ${itemData.type} ${itemData.isDone ? 'is-done' : ''}`;
                    itemEl.dataset.id = itemData.id;
                    itemEl.innerHTML = Render.itemHTML(itemData, { showProjectTag: false, isProjectView: true });
                    DOM.projectTaskList.appendChild(itemEl);
                });
            }

            if(DOM.projectTaskList._sortable) DOM.projectTaskList._sortable.destroy();
            DOM.projectTaskList._sortable = new Sortable(DOM.projectTaskList, {
                group: { name: 'matrix', pull: 'clone', put: false },
                animation: 150, handle: '.type-badge', ghostClass: 'sortable-ghost',
                filter: '.item-note-container', preventOnFilter: false,
                onStart: () => document.body.classList.add('is-dragging'),
                onEnd: (evt) => {
                    document.body.classList.remove('is-dragging');
                    const id = evt.item.dataset.id;
                    const toBlock = evt.to.closest('.day-block');

                    if (toBlock && !evt.to.closest('.drawer-panel')) {
                        const newDate = toBlock.dataset.date;
                        const newLane = evt.to.dataset.laneId;

                        if (newLane !== uiState.activeLaneProjects) {
                            Undo.showSystemToast("Tasks must be dropped into their active project lane.", false);
                            EventBus.emit('itemsChanged'); 
                            return;
                        }

                        Actions.mutate(() => {
                            const item = state.items.find(x => x.id === id);
                            if (item) { item.dateStr = newDate; item.laneId = newLane; }
                        }, 'itemsMoved', { oldDateStr: null, newDateStr: newDate });
                    }
                    else if (evt.to === DOM.projectTaskList && uiState.projSortMode === 'custom') {
                        const domIds = Array.from(DOM.projectTaskList.children).map(c => c.dataset.id).filter(Boolean);
                        Actions.mutate(() => {
                            const pTasks = []; const oTasks = [];
                            state.items.forEach(i => { if(i.projectId === uiState.activeProjectId) pTasks.push(i); else oTasks.push(i); });
                            pTasks.sort((a,b) => domIds.indexOf(a.id) - domIds.indexOf(b.id));
                            state.items = [...oTasks, ...pTasks];
                        }, 'silentSave');
                    } else if (uiState.projSortMode === 'date') {
                        Render.projectsDrawerUI(); 
                    }
                }
            });

        } else { 
            DOM.projectEmptyState.style.display = 'block'; DOM.projectEditor.style.display = 'none'; 
        }
    },

    projectsDrawerTabsOnly() {
        const laneProjs = state.projects.filter(p => p.laneId === uiState.activeLaneProjects);
        let tabsHtml = '';
        laneProjs.forEach(proj => {
            const isActive = proj.id === uiState.activeProjectId;
            tabsHtml += `
                <div class="drawer-tab action-btn ${isActive ? 'active' : ''}" role="button" tabindex="0" data-action="switchProject" data-id="${proj.id}" title="${Utils.escape(proj.title)}">
                    ${Utils.escape(proj.title) || 'Untitled'}
                    <span class="del-tab-btn action-btn" role="button" tabindex="0" data-action="deleteProject" data-id="${proj.id}" title="Delete Project">×</span>
                </div>
            `;
        });
        DOM.projectsTabs.innerHTML = tabsHtml;

        if(DOM.projectsTabs._sortable) DOM.projectsTabs._sortable.destroy();
        DOM.projectsTabs._sortable = new Sortable(DOM.projectsTabs, {
            animation: 150,
            onEnd: () => {
                const domIds = Array.from(DOM.projectsTabs.children).map(c => c.dataset.id).filter(Boolean);
                Actions.mutate(() => {
                    const activeProjs = [];
                    domIds.forEach(id => { const p = state.projects.find(x => x.id === id); if(p) activeProjs.push(p); });
                    const otherProjs = state.projects.filter(p => p.laneId !== uiState.activeLaneProjects);
                    state.projects = [...otherProjs, ...activeProjs]; 
                }, 'silentSave');
            }
        });
    },

    horizon() {
        let html = `<div class="empty-col"></div>`;
        state.lanes.forEach(lane => {
            const isMin = uiState.isProjectsOpen ? (lane.id !== uiState.activeLaneProjects) : lane.minimized;
            html += `
                <div class="horizon-col sl-${lane.id} ${isMin ? 'is-minimized' : ''}">
                    <div class="overdue-section" id="overdue-sec-${lane.id}">
                        <h4 class="overdue-header">Overdue</h4>
                        <div class="overdue-bin track" data-lane-id="${lane.id}" id="overdue-bin-${lane.id}"></div>
                    </div>
                    <div id="hz-${lane.id}"></div>
                </div>
            `;
        });
        html += `<div class="empty-col"></div><div id="horizon-span-filler" class="v-bound hide-in-proj-mode"></div>`;
        DOM.horizon.innerHTML = html;

        document.querySelectorAll('.overdue-bin').forEach(bin => DragDrop.initFor(bin));
        if(state.settings.showHorizon) { DOM.horizon.classList.add('is-expanded'); this.horizonData(); }
    },

    horizonData() {
        if(!state.settings.showHorizon) return;
        const sysToday = Utils.todayStr;

        state.lanes.forEach(lane => {
            const bin = document.getElementById(`overdue-bin-${lane.id}`);
            const sec = document.getElementById(`overdue-sec-${lane.id}`);
            if(bin && sec) {
                bin.innerHTML = '';
                const overdue = state.items.filter(i => i.laneId === lane.id && !i.isDone && i.dateStr && i.dateStr < sysToday);
                if (overdue.length > 0) {
                    overdue.forEach(itemData => {
                        const itemEl = document.createElement('div');
                        itemEl.className = `item sl-${lane.id} ${itemData.type} is-clone is-overdue`;
                        itemEl.dataset.id = itemData.id;
                        itemEl.innerHTML = Render.itemHTML(itemData, { showProjectTag: true, isReadonly: true });
                        bin.appendChild(itemEl);
                    });
                    sec.style.display = 'block';
                } else { sec.style.display = 'none'; }
            }

            const container = document.getElementById(`hz-${lane.id}`);
            if(container) {
                container.innerHTML = ''; 
                const ul = document.createElement('ul'); ul.className = 'index-list';
                const hzItems = state.items.filter(i => { return i.laneId === lane.id && i.dateStr && (i.type === 'type-outcome' || i.type === 'type-milestone' || i.type === 'type-event') && (i.dateStr >= sysToday || i.isDone); });
                const mapped = hzItems.map(item => { if (!state.settings.showAchievements && item.isDone) return null; return { ...item, diffDays: Utils.getDiffDays(item.dateStr) }; }).filter(i => i !== null).sort((a, b) => a.diffDays - b.diffDays);

                mapped.forEach(data => {
                    const li = document.createElement('li');
                    const typeConfig = Config.itemTypes.find(t => t.id === data.type) || Config.itemTypes[0];

                    let projBadge = '';
                    if (data.projectId) {
                        const p = state.projects.find(x => x.id === data.projectId);
                        if (p) projBadge = `<span class="proj-tag" title="${Utils.escape(p.title)}">${Utils.escape(p.title.substring(0,2).toUpperCase())}</span>`;
                    }

                    li.dataset.date = data.dateStr; li.dataset.id = data.id; li.classList.add('hz-item', data.type, `sl-${lane.id}`); 
                    if (data.type === 'type-milestone') li.classList.add('type-m-index');
                    if (data.isDone) li.classList.add('is-done');
                    let timeStr = data.diffDays > 0 ? `${data.diffDays}d` : (data.diffDays === 0 ? 'Today' : 'Past');

                    li.innerHTML = `
                        <div style="display:flex; align-items:center; padding-left:10px;">
                            <span class="type-badge action-btn" role="button" tabindex="0" data-action="cycleType" style="margin-right: 8px;">${typeConfig.label}</span>
                            ${projBadge}
                        </div>
                        <span class="index-text action-btn" role="button" tabindex="0" data-action="seekToDate" data-val="${data.dateStr}" data-id="${data.id}">${Utils.escape(data.text)}</span>
                        <span class="index-days">${timeStr}</span>
                    `;
                    ul.appendChild(li);
                });
                container.appendChild(ul);
            }
        });
        this.applyScrollFilter(); this.syncHorizonHeight(); 
    },

    syncHorizonHeight() {
        const hz = DOM.horizon; if(!state.settings.showHorizon) { hz.style.height = ''; return; }
        hz.style.height = 'auto'; 
        const gridSize = 44;
        hz.style.height = (Math.ceil(hz.scrollHeight / gridSize) * gridSize) + 'px';
    },

    buildDayBlock(dateStr) {
        const curDate = Utils.parseDate(dateStr); 
        const dayName = curDate.toLocaleString('default', { weekday: 'short' });
        const dayNum = curDate.getDate();
        const monthName = curDate.toLocaleString('default', { month: 'long' });
        const dow = curDate.getDay(); 

        const sysToday = Utils.todayStr;
        const isPast = dateStr < sysToday, isFuture = dateStr > sysToday, isToday = dateStr === sysToday;
        const monthStr = (dayNum === 1 || isToday) ? monthName.substring(0,3) + " '" + curDate.getFullYear().toString().substring(2) : '';

        const dayBlock = document.createElement('div');
        dayBlock.className = `grid-row day-block ${isToday?'is-today':''} ${isPast?'is-past':''} ${isFuture?'is-future':''} ${(dow===0||dow===6)?'is-weekend':''}`;
        dayBlock.dataset.date = dateStr; 

        let tracksHTML = ''; state.lanes.forEach(lane => {
            const isMin = uiState.isProjectsOpen ? (lane.id !== uiState.activeLaneProjects) : lane.minimized;
            tracksHTML += `<div class="track sl-${lane.id} ${isMin ? 'is-minimized' : ''}" data-lane-id="${lane.id}"></div>`;
        });

        let habitCellsHTML = ''; 
        if (state.settings.habitsMin) {
            habitCellsHTML = `<div class="habit-cell v-bound is-minimized-col hide-in-proj-mode action-btn" role="button" tabindex="0" data-action="toggleHabitsMin"></div>`;
        } else {
            state.habits.forEach((habit, idx) => {
                const isChecked = state.habitChecks[dateStr]?.[habit.id];
                habitCellsHTML += `
                <div class="habit-cell hide-in-proj-mode ${idx === 0 ? 'v-bound' : ''}">
                    <div class="cell-top">
                        <div class="habit-box action-btn ${isChecked ? 'is-checked' : ''}" role="button" tabindex="0" data-action="toggleHabit" data-date="${dateStr}" data-id="${habit.id}"></div>
                    </div>
                </div>`;
            });
            habitCellsHTML += `<div class="empty-col hide-in-proj-mode"></div>`;
        }

        let diaryCellHTML = '';
        if (state.settings.diaryMin) {
            diaryCellHTML = `<div class="diary-cell v-bound is-minimized-col hide-in-proj-mode action-btn" role="button" tabindex="0" data-action="toggleDiaryMin"></div>`;
        } else {
            diaryCellHTML = `
                <div class="diary-cell hide-in-proj-mode v-bound">
                    <div class="cell-top" style="width: 100%;">
                        <textarea class="diary-input action-input" rows="1" spellcheck="false" data-action="editDiary" data-date="${dateStr}">${Utils.escape(state.diary[dateStr] || '')}</textarea>
                    </div>
                </div>
            `;
        }

        dayBlock.innerHTML = `
            <div class="date-col">
                ${monthStr ? `<div class="month-label">${monthStr}</div>` : ''}
                <div class="cell-top" style="justify-content: flex-start;">
                    <span class="day-label">${dayName} ${dayNum}</span>
                    <span class="day-toggle action-btn" role="button" tabindex="0" data-action="toggleDay">▼</span>
                    <div class="dprog" id="dp-${dateStr}"><div class="dprog-fill"></div></div>
                </div>
            </div>
            ${tracksHTML}
            <div class="empty-col hide-in-proj-mode"></div>
            <div class="focus-cell hide-in-proj-mode v-bound" id="fc-${dateStr}"></div>
            ${habitCellsHTML}
            ${diaryCellHTML}
        `;
        dayMap.set(dateStr, dayBlock); return dayBlock;
    },

    trackContent(dateStr) {
        const dayBlock = dayMap.get(dateStr); if(!dayBlock) return;
        state.lanes.forEach(lane => {
            const track = dayBlock.querySelector(`.track.sl-${lane.id}`); if(!track) return;
            if (track.contains(document.activeElement)) return; 
            if (track._sortable) { track._sortable.destroy(); track._sortable = null; }
            track.innerHTML = '';
            state.items.filter(i => i.dateStr === dateStr && i.laneId === lane.id).forEach(itemData => {
                const itemEl = document.createElement('div');
                itemEl.className = `item sl-${lane.id} ${itemData.type} ${itemData.isDone ? 'is-done' : ''}`;
                itemEl.dataset.id = itemData.id;
                itemEl.innerHTML = Render.itemHTML(itemData, { showProjectTag: true }); 
                track.appendChild(itemEl);
            });
            DragDrop.initFor(track);
        });
    },

    itemHTML(itemData, opts = { showProjectTag: false, isReadonly: false, isProjectView: false }) {
        const typeConfig = Config.itemTypes.find(t => t.id === itemData.type) || Config.itemTypes[0];
        const isUrl = /^https?:\/\//i.test(itemData.text);
        const linkBtn = isUrl ? `<a href="${Utils.escape(itemData.text)}" target="_blank" class="url-btn action-btn" tabindex="-1">↗</a>` : '';

        let projBadge = '';
        if (opts.showProjectTag && itemData.projectId) {
            const p = state.projects.find(x => x.id === itemData.projectId);
            if (p) projBadge = `<span class="proj-tag" title="${Utils.escape(p.title)}">${Utils.escape(p.title.substring(0,2).toUpperCase())}</span>`;
        }

        const hasNote = itemData.note && itemData.note.trim() !== '';

        const textDisplay = opts.isReadonly 
            ? `<div class="text-input-readonly">${Utils.escape(itemData.text)}</div>`
            : `<input type="text" class="text-input action-input" value="${Utils.escape(itemData.text)}" autocomplete="off" spellcheck="false" data-action="editTask">`;

        const noteToggleBtn = opts.isReadonly 
            ? ``
            : `<div class="task-note-toggle action-btn ${hasNote ? 'has-note' : ''}" role="button" tabindex="0" data-action="toggleTaskNote" title="Task Note">▼</div>`;

        return `
            <div class="item-main">
                <span class="type-badge action-btn" role="button" tabindex="0" title="${opts.isReadonly ? 'Double-Tap to complete.' : 'Drag to move. Right-Click or Double-Tap to complete.'}" data-action="${opts.isReadonly ? '' : 'cycleType'}">${typeConfig.label}</span>
                ${projBadge}
                ${linkBtn}
                ${textDisplay}
                ${opts.isProjectView ? `<input type="date" class="proj-date-input action-input" data-action="editProjTaskDate" value="${itemData.dateStr || ''}">` : ''}
                <span class="countdown"></span>
                ${noteToggleBtn}
                <div class="del-item-btn action-btn" role="button" tabindex="0" data-action="deleteItem" title="Delete">×</div>
            </div>
            ${opts.isReadonly ? '' : `
            <div class="item-note-container nodrag">
                <div class="item-note-body action-input" contenteditable="true" spellcheck="false" data-action="editTaskNoteContent" placeholder="Task note...">${itemData.note || ''}</div>
                <div class="mini-toolbar">
                    <button class="fmt-btn-mini" onmousedown="event.preventDefault(); document.execCommand('bold',false,null);" title="Bold">B</button>
                    <button class="fmt-btn-mini" onmousedown="event.preventDefault(); document.execCommand('italic',false,null);" title="Italic">I</button>
                    <button class="fmt-btn-mini" onmousedown="event.preventDefault(); document.execCommand('insertUnorderedList',false,null);" title="List">•</button>
                </div>
            </div>`}
        `;
    },

    updateFocusDisplay(onlyToday = false) {
        const sysToday = Utils.todayStr;
