                    if (isRunning && dateStr === sysToday) {
                        totalMs += (Date.now() - fData.startTs);
                    }

                    if (dateStr === sysToday) {
                        cell.innerHTML = `
                            <div class="cell-top" style="flex-direction: column;">
                                <div class="focus-btn action-btn ${isRunning ? 'is-running' : ''}" role="button" data-action="toggleFocusTimer" data-date="${dateStr}">${isRunning ? '⏸' : '▶'}</div>
                                <div class="focus-time-display">${Utils.formatTime(totalMs)}</div>
                            </div>
                        `;
                    } else {
                        if (totalMs > 0) {
                            cell.innerHTML = `
                                <div class="cell-top">
                                    <div class="focus-stat-btn action-btn" role="button" data-action="showFocusStats" data-date="${dateStr}">${Utils.formatTime(totalMs)}</div>
                                </div>
                            `;
                        } else {
                            cell.innerHTML = ``;
                        }
                    }
                });
            },

            habitStats() {
                const sysToday = Utils.todayStr;
                state.habits.forEach((habit) => {
                    let count = 0, streakCount = 0;
                    const allDates = Object.keys(state.habitChecks).filter(d => d <= sysToday).sort().reverse();
                    for (const d of allDates) {
                        if (state.habitChecks[d]?.[habit.id]) { count++; streakCount++; } else if(state.settings.habitMode === 'streak') break;
                    }
                    const display = document.getElementById(`stat-${habit.id}`);
                    if(display) display.innerText = state.settings.habitMode === 'total' ? count : streakCount;
                });
            },

            updateDayToggles() {
                document.querySelectorAll('.day-block').forEach(block => {
                    const toggle = block.querySelector('.day-toggle'); 
                    let taskCount = 0;
                    block.querySelectorAll('.track').forEach(track => { taskCount += track.children.length; });

                    if(toggle) {
                        toggle.style.display = taskCount > 1 ? 'block' : 'none';
                        if (taskCount <= 1 && block.classList.contains('collapsed')) {
                            block.classList.remove('collapsed');
                            toggle.innerText = '▼';
                        }
                    }

                    block.querySelectorAll('.type-outcome, .type-event').forEach(outcome => {
                        const d = Utils.getDiffDays(block.dataset.date);
                        const span = outcome.querySelector('.countdown');
                        if(span) span.innerText = d > 0 ? `(${d}d)` : d === 0 ? `(Today)` : `(Past)`;
                    });
                });
            },

            updateProgress() {
                dayMap.forEach((block, dateStr) => {
                    const prog = document.getElementById(`dp-${dateStr}`); if(!prog) return;
                    const all = state.items.filter(i => i.dateStr === dateStr);
                    if(!all.length) { prog.classList.remove('show'); return; }
                    prog.classList.add('show');
                    prog.querySelector('.dprog-fill').style.width = Math.round(all.filter(i => i.isDone).length / all.length * 100) + '%';
                });
            },

            applyScrollFilter() {
                if (!state.settings.showHorizon) return;
                const hh = DOM.header.getBoundingClientRect().height;
                document.querySelectorAll('.index-list li[data-date]').forEach(li => {
                    const dayBlock = dayMap.get(li.dataset.date);
                    if (!dayBlock) { li.style.display = state.settings.horizonMode === 'scroll' ? 'none' : 'flex'; return; }
                    li.style.display = state.settings.horizonMode === 'all' ? 'flex' : (dayBlock.getBoundingClientRect().top > hh ? 'none' : 'flex');
                });
            }
        };

        const VirtualScroll = {
            pendingForward: false, pendingBackward: false,
            init() {
                this.reset();
                const observer = new IntersectionObserver((entries) => {
                    entries.forEach(entry => {
                        if(entry.isIntersecting) { if(entry.target.id === 'scroll-sentinel') this.pendingForward = true; if(entry.target.id === 'top-sentinel') this.pendingBackward = true; } 
                        else { if(entry.target.id === 'scroll-sentinel') this.pendingForward = false; if(entry.target.id === 'top-sentinel') this.pendingBackward = false; }
                    });
                    if (!isVirtualizing) this.processPending();
                }, { rootMargin: '400px' }); 
                observer.observe(DOM.bottomSentinel); observer.observe(DOM.topSentinel);
            },
            processPending() {
                if (isVirtualizing) return;
                if (this.pendingForward) this.loadForward(30); else if (this.pendingBackward) this.loadBackward(30);
            },
            reset() {
                renderStartDate = Utils.today; if (!state.settings.showAchievements) { renderStartDate.setDate(renderStartDate.getDate() - 1); } else { renderStartDate.setDate(renderStartDate.getDate() - 30); }
                renderEndDate = new Date(renderStartDate.getTime()); renderEndDate.setDate(renderEndDate.getDate() - 1); 
                this.loadForward(60); 
            },
            seekToDate(targetDateStr, highlightId = null) {
                if (!targetDateStr) return; 
                const target = Utils.parseDate(targetDateStr);
                const existing = dayMap.get(targetDateStr);
                const offset = DOM.header.offsetHeight + (state.settings.showHorizon ? DOM.horizon.offsetHeight : 0) + 20; 

                const executeScrollAndHighlight = (el) => {
                    el.classList.remove('collapsed');
                    window.scrollTo({top: el.getBoundingClientRect().top + window.scrollY - offset, behavior: 'smooth'});

                    if (highlightId) {
                        const itemEl = el.querySelector(`.item[data-id="${highlightId}"]`);
                        if (itemEl) {
                            itemEl.style.transition = 'background 0.4s ease';
                            itemEl.style.backgroundColor = 'rgba(59, 130, 246, 0.15)';
                            itemEl.style.borderRadius = '6px';
                            setTimeout(() => { itemEl.style.backgroundColor = 'transparent'; }, 1500);
                            setTimeout(() => { itemEl.style.transition = ''; }, 2000); 
                        }
                    }
                };

                if (existing && document.body.contains(existing)) {
                    setTimeout(() => executeScrollAndHighlight(existing), 10);
                    return;
                }

                DOM.body.innerHTML = ''; dayMap.clear();
                renderStartDate = new Date(target.getTime()); renderStartDate.setDate(renderStartDate.getDate() - 15);
                renderEndDate = new Date(renderStartDate.getTime()); renderEndDate.setDate(renderEndDate.getDate() - 1); 
                this.loadForward(40);
                setTimeout(() => { 
                    const el = dayMap.get(targetDateStr); 
                    if(el) executeScrollAndHighlight(el);
                }, 50);
            },
            loadForward(count) {
                isVirtualizing = true; const frag = document.createDocumentFragment(); const datesAdded = [];
                for(let i=0; i<count; i++) { renderEndDate.setDate(renderEndDate.getDate() + 1); const dStr = Utils.toLocalISO(renderEndDate); frag.appendChild(Render.buildDayBlock(dStr)); datesAdded.push(dStr); }
                DOM.body.appendChild(frag); datesAdded.forEach(dStr => Render.trackContent(dStr)); Render.updateDayToggles(); Render.updateProgress(); Render.updateFocusDisplay();
                this.cleanupTop(); requestAnimationFrame(() => { requestAnimationFrame(() => { isVirtualizing = false; this.processPending(); }); });
            },
            loadBackward(count) {
                if (!state.settings.showAchievements && renderStartDate <= Utils.today) { this.pendingBackward = false; return; }
                isVirtualizing = true; const frag = document.createDocumentFragment(); const datesAdded = [];
                for(let i=0; i<count; i++) { renderStartDate.setDate(renderStartDate.getDate() - 1); datesAdded.unshift(Utils.toLocalISO(renderStartDate)); }
                datesAdded.forEach(dStr => frag.appendChild(Render.buildDayBlock(dStr)));
                const oldScroll = document.documentElement.scrollHeight; const oldTop = window.scrollY;
                DOM.body.insertBefore(frag, DOM.body.firstChild); datesAdded.forEach(dStr => Render.trackContent(dStr)); Render.updateDayToggles(); Render.updateProgress(); Render.updateFocusDisplay();
                window.scrollTo(0, oldTop + (document.documentElement.scrollHeight - oldScroll)); this.cleanupBottom();
                requestAnimationFrame(() => { requestAnimationFrame(() => { isVirtualizing = false; this.processPending(); }); });
            },
            cleanupTop() {
                const days = document.querySelectorAll('.day-block');
                if(days.length > Config.maxRenderedDays) {
                    const toRemove = days.length - Config.maxRenderedDays; let removedHeight = 0;
                    for(let i=0; i<toRemove; i++) { removedHeight += days[i].offsetHeight; days[i].querySelectorAll('.track').forEach(t => { if(t._sortable) t._sortable.destroy(); }); dayMap.delete(days[i].dataset.date); days[i].remove(); }
                    renderStartDate = Utils.parseDate(days[toRemove].dataset.date); window.scrollBy(0, -removedHeight);
                }
            },
            cleanupBottom() {
                const days = document.querySelectorAll('.day-block');
                if(days.length > Config.maxRenderedDays) {
                    const toRemove = days.length - Config.maxRenderedDays;
                    for(let i=days.length-1; i >= days.length - toRemove; i--) { days[i].querySelectorAll('.track').forEach(t => { if(t._sortable) t._sortable.destroy(); }); dayMap.delete(days[i].dataset.date); days[i].remove(); }
                    renderEndDate = Utils.parseDate(days[days.length-toRemove-1].dataset.date);
                }
            }
        };

        const DragDrop = {
            initFor(trackEl) {
                if (!trackEl._sortable) {
                    trackEl._sortable = new Sortable(trackEl, {
                        group: 'matrix', animation: 150, handle: '.type-badge', ghostClass: 'sortable-ghost',
                        filter: '.item-note-container', preventOnFilter: false,
                        onStart: () => document.body.classList.add('is-dragging'),
                        onEnd: function(evt) { 
                            document.body.classList.remove('is-dragging');
                            const id = evt.item.dataset.id; const toBlock = evt.to.closest('.day-block');
                            if (!state.items.find(i => i.id === id)) { EventBus.emit('itemsChanged'); return; }
                            if (toBlock && !evt.to.classList.contains('overdue-bin')) {
                                const domIds = Array.from(evt.to.children).map(child => child.dataset.id).filter(Boolean);
                                Actions.reorderTrack(id, toBlock.dataset.date, evt.to.dataset.laneId, domIds);
                            } else { EventBus.emit('itemsChanged'); }
                        } 
                    });
                }
            }
        };

        const Search = {
            init() {
                let searchTimer;
                DOM.searchInput.addEventListener('input', (e) => { clearTimeout(searchTimer); searchTimer = setTimeout(() => this.query(e.target.value), 200); });
                document.addEventListener('keydown', (e) => {
                    if((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); this.toggle(); }
                    if(e.key === 'Escape' && DOM.searchOverlay.classList.contains('is-open')) this.toggle(false);
                });
                DOM.searchOverlay.addEventListener('click', (e) => { if(e.target === DOM.searchOverlay) this.toggle(false); });
                document.getElementById('focus-stats-overlay').addEventListener('click', (e) => { if(e.target.id === 'focus-stats-overlay') document.getElementById('focus-stats-overlay').classList.remove('is-open'); });
            },
            toggle(forceState) {
                const isOpen = forceState !== undefined ? forceState : !DOM.searchOverlay.classList.contains('is-open');
                DOM.searchOverlay.classList.toggle('is-open', isOpen);
                if(isOpen) { DOM.searchInput.value = ''; DOM.searchResults.innerHTML = ''; setTimeout(() => DOM.searchInput.focus(), 50); }
            },
            query(text) {
                DOM.searchResults.innerHTML = ''; if(text.trim().length < 2) return;
                const lower = text.toLowerCase(); const results = [];
                state.items.forEach(i => { 
                    if(i.text.toLowerCase().includes(lower) || (i.note && i.note.toLowerCase().includes(lower))) {
                        results.push({ d: i.dateStr || 'Backlog', t: i.text, type: 'Task', id: i.id }); 
                    }
                });
                Object.keys(state.diary).forEach(d => { if(state.diary[d].toLowerCase().includes(lower)) { let snippet = state.diary[d]; if (snippet.length > 80) snippet = snippet.substring(0, 80) + '...'; results.push({ d: d, t: snippet, type: 'Diary' }); } });

                results.sort((a,b) => {
                    const dateA = a.d || '';
                    const dateB = b.d || '';
                    return dateB.localeCompare(dateA);
                }).slice(0, 15).forEach(res => {
                    const li = document.createElement('li'); li.className = 'search-item';
                    const displayDate = res.d ? res.d : 'Backlog';
                    li.innerHTML = `<span class="search-item-date">${displayDate} &middot; ${res.type}</span><span class="search-item-text">${Utils.escape(res.t)}</span>`;
                    li.addEventListener('click', () => { 
                        this.toggle(false); 
                        if (res.d === 'Backlog') { Actions.openProjects(state.lanes[0].id); } 
                        else { VirtualScroll.seekToDate(res.d, res.id); }
                    });
                    DOM.searchResults.appendChild(li);
                });
            }
        };

        function BusWrap(evt, cb) { EventBus.on(evt, cb); }

        const Events = {
            bind() {
                window.addEventListener('beforeunload', () => { clearTimeout(saveTimer); Store.save(); });
                document.addEventListener('visibilitychange', () => { if (document.visibilityState === 'hidden') { clearTimeout(saveTimer); Store.save(); } });

                DOM.importUpload.addEventListener('change', (e) => {
                    const file = e.target.files[0]; if (!file) return;
                    const reader = new FileReader();
                    reader.onload = async (ev) => { 
                        try { 
                            const data = JSON.parse(ev.target.result); 
                            if (data && data.version) { 
                                Undo.snap('Import Backup'); 
                                Store.hydrate(data); 
                                await Store.save(); 
                                location.reload(); 
                            } else alert("Invalid backup file."); 
                        } catch(err) { alert("Error reading file."); }
                        e.target.value = ''; 
                    }; reader.readAsText(file);
                });

                document.addEventListener('click', (e) => {
                    if(e.target.tagName === 'A' && (e.target.closest('#note-text-input') || e.target.closest('.item-note-body'))) {
                        window.open(e.target.href, '_blank');
                    }

                    if(e.target.closest('#btn-link')) {
                        e.preventDefault();
                        const url = prompt('Enter link URL (including https://):', 'https://');
                        if(url) { document.execCommand('createLink', false, url); DOM.noteBodyInput.dispatchEvent(new Event('input', {bubbles:true})); }
                    }

                    if(e.target === DOM.projectEditor || e.target === DOM.projectTaskList) {
                        if(uiState.isProjectsOpen && uiState.activeProjectId) {
                            Actions.addProjectTask(uiState.activeProjectId);
                        }
                    }

                    const btn = e.target.closest('.action-btn');
                    if(btn) {
                        const action = btn.dataset.action;
                        if (e.type === 'click' && btn.getAttribute('role') === 'button') { e.target.blur(); } 

                        if(action === 'toggleSettings') document.getElementById('settings-tray').classList.toggle('is-open');
                        if(action === 'setTheme') Actions.toggleSetting('theme', btn.dataset.val);
                        if(action === 'setHzMode') Actions.toggleSetting('horizonMode', btn.dataset.val);
                        if(action === 'toggleAchievements') Actions.toggleAchievement();
                        if(action === 'toggleHorizon') { if (!state.settings.showHorizon) VirtualScroll.seekToDate(Utils.todayStr); Actions.toggleHorizon(); }
                        if(action === 'toggleHabitsMin') Actions.toggleHabitsMin();
                        if(action === 'toggleDiaryMin') Actions.toggleDiaryMin();
                        if(action === 'closeOnboarding') { DOM.onboarding.classList.remove('is-open'); localStorage.setItem('swimlane_onboarded', 'true'); }
                        if(action === 'showOnboarding') DOM.onboarding.classList.add('is-open');

                        if(action === 'exportData') Actions.exportData();
                        if(action === 'importData') Actions.importData();

                        if(action === 'scrollToToday') VirtualScroll.seekToDate(Utils.todayStr);
                        if(action === 'seekToDate') VirtualScroll.seekToDate(btn.dataset.val, btn.dataset.id);

                        if(action === 'minLane') Actions.minLane(btn.dataset.id);
                        if(action === 'delLane') Actions.delLane(btn.dataset.id);
                        if(action === 'addLane') Actions.addLane();
                        if(action === 'cycleColor') Actions.cycleLaneColor(btn.dataset.id);

                        if(action === 'toggleHabit') { const nowChecked = !btn.classList.contains('is-checked'); btn.classList.toggle('is-checked', nowChecked); Actions.toggleHabit(btn.dataset.date, btn.dataset.id, nowChecked); }
                        if(action === 'setHabMode') Actions.toggleSetting('habitMode', btn.dataset.val);
                        if(action === 'addHabit') Actions.addHabit();

                        if(action === 'toggleFocusTimer') Actions.toggleFocusTimer(btn.dataset.date);
                        if(action === 'showFocusStats') Actions.showFocusStats(btn.dataset.date);
                        if(action === 'closeFocusStats') document.getElementById('focus-stats-overlay').classList.remove('is-open');

                        if(action === 'cycleType') Actions.cycleType(btn.closest('.item, .hz-item').dataset.id);
                        if(action === 'deleteItem') Actions.deleteItem(btn.closest('.item').dataset.id);
                        if(action === 'toggleTaskNote') {
                            const itemEl = btn.closest('.item');
                            itemEl.classList.toggle('is-expanded');
                            if(itemEl.classList.contains('is-expanded')) {
                                setTimeout(() => {
                                    const body = itemEl.querySelector('.item-note-body');
                                    if(body) body.focus();
                                    Render.snapItemHeight(itemEl);
                                }, 10);
                            } else {
                                itemEl.style.height = ''; 
                            }
                        }

                        if(action === 'toggleDay') { 
                            const b = btn.closest('.day-block'); 
                            b.classList.toggle('collapsed'); 
                            btn.innerText = b.classList.contains('collapsed') ? '▶' : '▼'; 
                        }

                        if(action === 'openNotes') Actions.openNotes(btn.dataset.id);
                        if(action === 'closeNotes') Actions.closeNotes();
                        if(action === 'addNote') Actions.addNote();
                        if(action === 'switchNote') Actions.switchNote(btn.dataset.id);
                        if(action === 'deleteNote') { Actions.deleteNote(btn.dataset.id); e.stopPropagation(); return; }

                        if(action === 'toggleProjectsGlobal') Actions.toggleProjectsGlobal();
                        if(action === 'openProjects') Actions.openProjects(btn.dataset.id);
                        if(action === 'closeProjects') Actions.closeProjects();
                        if(action === 'addProject') Actions.addProject();
                        if(action === 'switchProject') Actions.switchProject(btn.dataset.id);
                        if(action === 'deleteProject') { Actions.deleteProject(btn.dataset.id); e.stopPropagation(); return; }
                        if(action === 'setProjSort') Actions.setProjSort(btn.dataset.val);
                        if(action === 'addProjectTaskFirst') Actions.addProjectTask(uiState.activeProjectId);

                        return;
                    }

                    if (!e.target.closest('.control-panel') && !e.target.closest('.search-modal') && !e.target.closest('.onboarding-modal') && !e.target.closest('.drawer-panel')) { const t = document.getElementById('settings-tray'); if(t) t.classList.remove('is-open'); }

                    const track = e.target.closest('.track');
                    if (track && !track.classList.contains('is-minimized') && !track.classList.contains('overdue-bin') && e.target === track) Actions.addItem(track.closest('.day-block').dataset.date, track.dataset.laneId);
                });

                document.addEventListener('contextmenu', (e) => {
                    const itemEl = e.target.closest('.item') || e.target.closest('.hz-item'); 
                    if(itemEl) { e.preventDefault(); Actions.toggleDone(itemEl.dataset.id); return; }
                    const hab = e.target.closest('.habit-header-col'); if(hab) { e.preventDefault(); Actions.delHabit(hab.querySelector('.action-contenteditable').dataset.id); }
                });

                let lastTap = 0;
                document.addEventListener('touchend', (e) => {
                    if (!e.target.closest('.track') && !e.target.closest('.proj-task-list')) return; 
                    const itemEl = e.target.closest('.item');
                    if (itemEl && !e.target.classList.contains('action-input') && !e.target.classList.contains('action-btn')) {
                        const currentTime = new Date().getTime();
                        if (currentTime - lastTap < 500 && currentTime - lastTap > 0) { Actions.toggleDone(itemEl.dataset.id); e.preventDefault(); }
                        lastTap = currentTime;
                    }
                });

                document.addEventListener('input', (e) => {
                    if(e.target.classList.contains('action-input')) {
                        const action = e.target.dataset.action;
                        if(action === 'editLaneTitle') Actions.updateLaneTitle(e.target.dataset.id, e.target.value);
                        if(action === 'editDiary') Actions.updateDiary(e.target.dataset.date, e.target.value);
                        if(action === 'editTask') {
                            const id = e.target.closest('.item').dataset.id;
                            document.querySelectorAll(`.item[data-id="${id}"] .text-input`).forEach(el => { if(el !== e.target) el.value = e.target.value; });
                            clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateTaskText(id, e.target.value), 300);
                        }
                        if(action === 'editTaskNoteContent') {
                            const itemEl = e.target.closest('.item');
                            const id = itemEl.dataset.id;
                            clearTimeout(e.target._saveTimer); 
                            e.target._saveTimer = setTimeout(() => Actions.updateTaskNote(id, e.target.innerHTML), 300);
                            Render.snapItemHeight(itemEl);
                        }
                        if(action === 'editNoteTitle') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateNoteTitle(uiState.activeNoteId, e.target.value), 200); }
                        if(action === 'editNoteBody') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateNoteBody(uiState.activeNoteId, e.target.innerHTML), 300); }
                        if(action === 'editProjectTitle') { clearTimeout(e.target._saveTimer); e.target._saveTimer = setTimeout(() => Actions.updateProjectTitle(uiState.activeProjectId, e.target.value), 200); }
                    }
                });

                document.addEventListener('change', (e) => {
                    if(e.target.dataset.action === 'editProjTaskDate') { 
                        const id = e.target.closest('[data-id]').dataset.id;
                        Actions.editItemDate(id, e.target.value); 
                    }
                });

                document.addEventListener('selectionchange', () => {
                    if(document.activeElement === DOM.noteBodyInput || (document.activeElement && document.activeElement.classList.contains('item-note-body'))) {
                        document.querySelectorAll('#btn-bold, .fmt-btn-mini[title="Bold"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('bold')));
                        document.querySelectorAll('#btn-italic, .fmt-btn-mini[title="Italic"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('italic')));
                        document.querySelectorAll('#btn-list, .fmt-btn-mini[title="List"]').forEach(b => b.classList.toggle('is-active', document.queryCommandState('insertUnorderedList')));
                    }
                });

                document.addEventListener('focusout', (e) => {
                    if(e.target.classList.contains('action-contenteditable')) { const val = e.target.innerText.trim(); Actions.updateHabitTitle(e.target.dataset.id, val); e.target.innerText = val || 'Habit'; }
                    if(e.target.classList.contains('text-input')) { setTimeout(() => { const itemEl = e.target.closest('.item'); if(itemEl && !itemEl.contains(document.activeElement)) Actions.sweepEmpty(itemEl.dataset.id); }, 50); }
                });

                document.addEventListener('paste', (e) => {
                    const text = (e.clipboardData || window.clipboardData).getData('text/plain');
                    if(e.target.classList.contains('item-note-body') || e.target.classList.contains('note-editor-body')) {
                        e.preventDefault();
                        document.execCommand('insertText', false, text);
                        return;
                    }
                    if(e.target.classList.contains('action-contenteditable')) {
                        e.preventDefault(); const selection = window.getSelection(); if (!selection.rangeCount) return;
                        selection.deleteFromDocument(); selection.getRangeAt(0).insertNode(document.createTextNode(text)); selection.collapseToEnd();
                        Actions.updateHabitTitle(e.target.dataset.id, e.target.innerText.trim());
                    } else if (e.target.classList.contains('diary-input')) {
                        e.preventDefault(); const start = e.target.selectionStart; const end = e.target.selectionEnd;
                        e.target.value = e.target.value.substring(0, start) + text + e.target.value.substring(end);
                        e.target.selectionStart = e.target.selectionEnd = start + text.length; Actions.updateDiary(e.target.dataset.date, e.target.value);
                    }
                });

                document.addEventListener('keydown', (e) => {
                    if((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) { if(!e.target.matches('input, textarea, [contenteditable]')) { e.preventDefault(); Undo.perform(); return; } }
                    if(e.target.classList.contains('action-contenteditable') && e.key === 'Enter') { e.preventDefault(); e.target.blur(); }
                    if(e.target.getAttribute('role') === 'button' && e.key === 'Enter') { e.target.click(); }
                    if (e.target.dataset.action === 'editTask') {
                        const itemEl = e.target.closest('.item'); const id = itemEl.dataset.id;
                        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') { Actions.toggleDone(id); return; }
                        if (e.key === 'Enter') {
                            e.preventDefault(); e.target.blur(); 
                            const track = itemEl.closest('.track');
                            const projList = itemEl.closest('.proj-task-list');
                            if(track && !track.classList.contains('overdue-bin')) { Actions.addItem(track.closest('.day-block').dataset.date, track.dataset.laneId); const block = itemEl.closest('.day-block'); if(block) block.classList.remove('collapsed'); }
                            else if(projList) { Actions.addProjectTask(uiState.activeProjectId); }
                        }
                        if (e.key === 'Backspace' && e.target.value === '') { e.preventDefault(); const prev = itemEl.previousElementSibling; Actions.deleteItem(id); if (prev && prev.classList.contains('item')) prev.querySelector('.text-input').focus(); }
                    }
                });

                document.getElementById('undo-btn').addEventListener('click', () => Undo.perform());
                setInterval(() => { const freshToday = Utils.todayStr; if(freshToday !== currentUiToday) { currentUiToday = freshToday; Actions.softRollover(); } }, 60000);

                let scrollTimeout; window.addEventListener('scroll', () => { if(state.settings.showHorizon && state.settings.horizonMode === 'scroll') { if(scrollTimeout) cancelAnimationFrame(scrollTimeout); scrollTimeout = requestAnimationFrame(() => Render.applyScrollFilter()); } });
            }
        };

        async function bootstrap() {
            try { await Store.init(); await Store.load(); } catch(e) { console.error("Boot Failed", e); }
            applySettings(); Render.init(); VirtualScroll.init(); Search.init(); Events.bind();
            if (!localStorage.getItem('swimlane_onboarded')) DOM.onboarding.classList.add('is-open');
            const t = document.querySelector('.is-today'); if(t) setTimeout(() => window.scrollTo({top: t.getBoundingClientRect().top + window.scrollY - 150, behavior: 'smooth'}), 50);
        }

        return { init: bootstrap };
    })();

    App.init();

</script>
</body>

