621	        const EventBus = {
622	            listeners: {},
623	            on(event, cb) { if(!this.listeners[event]) this.listeners[event] = []; this.listeners[event].push(cb); },
624	            off(event, cb) { if(this.listeners[event]) this.listeners[event] = this.listeners[event].filter(l => l !== cb); },
625	            clear() { this.listeners = {}; },
626	            emit(event, data) { if(this.listeners[event]) this.listeners[event].forEach(cb => cb(data)); }
627	        };
628	
629	        let undoTimer;
630	        const Undo = {
631	            stack: [], max: 20,
632	            snap(label = 'Action') {
633	                this.stack.push({ label, stateData: JSON.parse(JSON.stringify(state)) });
634	                if(this.stack.length > this.max) this.stack.shift();
635	            },
636	            perform() {
637	                if(!this.stack.length) return;
638	                const snap = this.stack.pop();
639	                state = snap.stateData;
640	                Store.save(); applySettings(); Render.hardRebuild();
641	                this.showToast('Undid: ' + snap.label);
642	            },
643	            showToast(msg) {
644	                document.getElementById('undo-msg').innerText = msg;
645	                DOM.toast.classList.add('is-active');
646	                clearTimeout(undoTimer); undoTimer = setTimeout(() => DOM.toast.classList.remove('is-active'), 3500);
647	            }
648	        };
