650	        const Store = {
651	            useIDB: false, db: null,
652	            init() {
653	                // Keep IndexedDB init to check for legacy client data to migrate
654	                return new Promise((resolve) => {
655	                    try {
656	                        if (!window.indexedDB) return resolve();
657	                        const req = indexedDB.open(Config.dbName, 1);
658	                        req.onupgradeneeded = e => { e.target.result.createObjectStore('state'); };
659	                        req.onsuccess = e => { this.db = e.target.result; this.useIDB = true; resolve(); };
660	                        req.onerror = e => { resolve(); };
661	                    } catch (e) { resolve(); }
662	                });
