    },
    updateTaskText(id, text) { 
        const item = state.items.find(x => x.id === id); 
        if(item) {
            this.mutate(() => { item.text = text; }, (item.type === 'type-outcome' || item.type === 'type-milestone') ? 'horizonChanged' : 'silentSave'); 
        }
    },
    toggleDone(id) { 
        Undo.snap('Toggle Done');
        this.mutate(() => { const i = state.items.find(x => x.id === id); if(i) i.isDone = !i.isDone; }, 'itemToggled', { id }); 
    },
    cycleType(id) { 
        const item = state.items.find(x => x.id === id);
        if (item) {
            Undo.snap('Cycle Type');
            this.mutate(() => { 
                let idx = Config.itemTypes.findIndex(t => t.id === item.type); 
                item.type = Config.itemTypes[(idx + 1) % Config.itemTypes.length].id; 
            }, 'itemsChanged', { dateStr: item.dateStr }); 
        }
    },
    deleteItem(id) { 
        const item = state.items.find(x => x.id === id);
        if (item) { Undo.snap('Delete Task'); this.mutate(() => { state.items = state.items.filter(x => x.id !== id); }, 'itemsChanged', { dateStr: item.dateStr }); }
    },
    reorderTrack(id, newDate, newLane, domIds) {
        const item = state.items.find(x => x.id === id);
        if (!item) return;
        const oldDateStr = item.dateStr;
        Undo.snap('Move Task');
        this.mutate(() => {
            item.dateStr = newDate; item.laneId = newLane;
            const trackItems = []; const otherItems = [];
            state.items.forEach(i => { if (domIds.includes(i.id)) trackItems.push(i); else otherItems.push(i); });
            trackItems.sort((a, b) => domIds.indexOf(a.id) - domIds.indexOf(b.id));
            state.items = [...otherItems, ...trackItems];
        }, 'itemsMoved', { oldDateStr, newDateStr: newDate });
    },
    sweepEmpty(id) { const i = state.items.find(x => x.id === id); if(i && i.text.trim() === '') this.deleteItem(id); },

    softRollover() {
        const sysToday = Utils.todayStr;
        document.querySelectorAll('.day-block').forEach(block => {
            const d = block.dataset.date;
            block.classList.toggle('is-today', d === sysToday);
            block.classList.toggle('is-past', d < sysToday);
            block.classList.toggle('is-future', d > sysToday);
        });
        EventBus.emit('horizonChanged'); EventBus.emit('itemsChanged'); 
    },

    openNotes(laneId) {
        uiState.isNotesOpen = true; uiState.activeLaneNotes = laneId;
        const laneNotes = state.notes.filter(n => n.laneId === laneId);
        if (laneNotes.length > 0) { if (!uiState.activeNoteId || !laneNotes.find(n => n.id === uiState.activeNoteId)) uiState.activeNoteId = laneNotes[0].id; } 
        else { uiState.activeNoteId = null; }
        Render.notesDrawerUI(); DOM.notesOverlay.classList.add('is-active'); DOM.notesDrawer.classList.add('is-open');
    },
    closeNotes() { uiState.isNotesOpen = false; DOM.notesOverlay.classList.remove('is-active'); DOM.notesDrawer.classList.remove('is-open'); },
    addNote() {
        if (!uiState.activeLaneNotes) return;
        Undo.snap('Add Note');
        const newNote = { id: Utils.uuid(), laneId: uiState.activeLaneNotes, title: 'New Note', content: '' };
        this.mutate(() => { state.notes.push(newNote); uiState.activeNoteId = newNote.id; }, 'notesChanged');
    },
    switchNote(id) { if (uiState.activeNoteId !== id) { uiState.activeNoteId = id; Render.notesDrawerUI(); } },
    deleteNote(id) {
        if(confirm("Delete this note?")) {
            Undo.snap('Delete Note');
            this.mutate(() => {
                state.notes = state.notes.filter(n => n.id !== id);
                if (uiState.activeNoteId === id) { const remaining = state.notes.filter(n => n.laneId === uiState.activeLaneNotes); uiState.activeNoteId = remaining.length > 0 ? remaining[0].id : null; }
            }, 'notesChanged');
        }
    },
    updateNoteTitle(id, title) { this.mutate(() => { const n = state.notes.find(x => x.id === id); if(n) n.title = title || 'Untitled'; }, 'notesTabsChanged'); },
    updateNoteBody(id, content) { this.mutate(() => { const n = state.notes.find(x => x.id === id); if(n) n.content = content; }, 'silentSave'); },

    exportData() {
        const b = new Blob([JSON.stringify(state, null, 2)], {type: "application/json"});
        const url = URL.createObjectURL(b); const a = document.createElement('a');
        a.href = url; a.download = `swimlane_backup_${Utils.todayStr}.json`;
        a.click(); URL.revokeObjectURL(url);
    },
    importData() { DOM.importUpload.click(); }
};

