    EventBus.clear();
    this.gridCSS(); this.header(); this.horizon();

    BusWrap('structureChanged', () => this.hardRebuild());
    BusWrap('settingsChanged', () => { applySettings(); this.header(); this.horizonData(); });
    BusWrap('horizonToggled', () => {
        const btn = document.querySelector('[data-action="toggleHorizon"]');
        if(btn) btn.classList.toggle('active', state.settings.showHorizon);
        DOM.horizon.classList.toggle('is-expanded', state.settings.showHorizon);
        if(state.settings.showHorizon) { VirtualScroll.seekToDate(Utils.todayStr); this.horizonData(); }
        this.syncHorizonHeight();
        if (window.scrollY > DOM.header.offsetHeight) window.scrollBy(0, state.settings.showHorizon ? DOM.horizon.offsetHeight : -DOM.horizon.scrollHeight);
    });

    BusWrap('itemsChanged', (p) => { 
        if(p && p.dateStr) this.trackContent(p.dateStr); else dayMap.forEach((_, dStr) => this.trackContent(dStr)); 
        this.horizonData(); this.updateDayToggles(); this.updateProgress();
    });
    BusWrap('itemsMoved', (p) => {
        if(p) { this.trackContent(p.oldDateStr); if(p.oldDateStr !== p.newDateStr) this.trackContent(p.newDateStr); }
        this.horizonData(); this.updateDayToggles(); this.updateProgress();
    });
    BusWrap('itemToggled', (p) => {
        if(p && p.id) {
            const item = state.items.find(i => i.id === p.id);
            if(item) document.querySelectorAll(`.item[data-id="${p.id}"]`).forEach(el => el.classList.toggle('is-done', item.isDone));
        }
        this.horizonData(); this.updateProgress();
    });
    BusWrap('horizonChanged', () => this.horizonData());
    BusWrap('habitsChanged', () => this.habitStats());

    BusWrap('notesChanged', () => { if(uiState.isNotesOpen) this.notesDrawerUI(); });
    BusWrap('notesTabsChanged', () => { if(uiState.isNotesOpen) this.notesDrawerTabsOnly(); });
},

hardRebuild() {
    const activeId = document.activeElement?.dataset?.id;
    DOM.body.innerHTML = ''; dayMap.clear();
    this.gridCSS(); this.header(activeId ? `[data-id="${activeId}"]` : null); this.horizon();
    VirtualScroll.seekToDate(Utils.todayStr);
},

gridCSS() {
    const laneWidth = state.lanes.length > 3 ? 'minmax(220px, 1fr)' : 'minmax(140px, 1fr)';
    const laneStr = state.lanes.map(sl => sl.minimized ? 'var(--grid-size)' : laneWidth).join(' ');
    const habitStr = `repeat(${state.habits.length}, var(--grid-size))`;
    const gridTemplate = `var(--left-margin) ${laneStr} var(--grid-size) ${habitStr} var(--grid-size) minmax(200px, 1.5fr)`;

    let css = `.grid-row { grid-template-columns: ${gridTemplate}; } #horizon-span-filler { grid-column: span ${state.habits.length + 2}; }`;
    state.lanes.forEach((l, i) => { css += `.sl-${l.id} { --lc: ${l.color || Config.PAL[i % Config.PAL.length]}; }`; });

    let styleTag = document.getElementById('dynamic-grid-style');
    if(!styleTag) { styleTag = document.createElement('style'); styleTag.id = 'dynamic-grid-style'; document.head.appendChild(styleTag); }
    styleTag.innerHTML = css;
},

header(activeFocusSelector = null) {
    let html = `
        <div class="control-panel">
            <div class="settings-wrapper">
                <div class="ui-btn action-btn" role="button" tabindex="0" data-action="toggleSettings">⚙ Options</div>
                <div class="settings-tray" id="settings-tray">
                    <div class="tray-section"><span class="tray-label">Paper Style</span>
                        <div class="tray-toggle-group">
                            <div class="tray-toggle-btn action-btn ${state.settings.theme==='dotted'?'active':''}" role="button" tabindex="0" data-action="setTheme" data-val="dotted">Dotted</div>
                            <div class="tray-toggle-btn action-btn ${state.settings.theme==='lined'?'active':''}" role="button" tabindex="0" data-action="setTheme" data-val="lined">Lined</div>
                        </div>
                    </div>
                    <div class="tray-section"><span class="tray-label">Horizon Filter</span>
                        <div class="tray-toggle-group">
                            <div class="tray-toggle-btn action-btn ${state.settings.horizonMode==='all'?'active':''}" role="button" tabindex="0" data-action="setHzMode" data-val="all">All</div>
                            <div class="tray-toggle-btn action-btn ${state.settings.horizonMode==='scroll'?'active':''}" role="button" tabindex="0" data-action="setHzMode" data-val="scroll">Scrolled</div>
                        </div>
                    </div>
                    <div class="tray-section"><span class="tray-label">Data Backup</span>
                        <div class="tray-toggle-group">
                            <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="exportData">Export</div>
                            <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="importData">Import</div>
                        </div>
                    </div>
                    <div class="tray-section"><span class="tray-label">Help</span>
                        <div class="tray-toggle-btn action-btn" role="button" tabindex="0" data-action="showOnboarding">Tutorial</div>
                    </div>
                </div>
            </div>
            <div class="ui-btn action-btn ${state.settings.showHorizon?'active':''}" role="button" tabindex="0" data-action="toggleHorizon">Horizon</div>
            <div class="ui-btn action-btn ${state.settings.showAchievements?'active':''}" role="button" tabindex="0" data-action="toggleAchievements">See Past</div>
            <div class="ui-btn action-btn" role="button" tabindex="0" data-action="scrollToToday">Today ↓</div>
        </div>
    `;

    state.lanes.forEach(lane => {
        html += `
            <div class="header-track sl-${lane.id} ${lane.minimized ? 'is-minimized' : ''}">
                <div class="track-controls">
                    <div class="ctrl-btn cdot action-btn" style="background:${lane.color}" role="button" tabindex="0" data-action="cycleColor" data-id="${lane.id}" title="Color"></div>
                    <div class="ctrl-btn action-btn" role="button" tabindex="0" data-action="minLane" data-id="${lane.id}" title="Minimize">-</div>
                    <div class="ctrl-btn action-btn" role="button" tabindex="0" data-action="openNotes" data-id="${lane.id}" title="Lane Notes">📝</div>
                    <div class="ctrl-btn del action-btn" role="button" tabindex="0" data-action="delLane" data-id="${lane.id}" title="Delete">×</div>
                </div>
                <input class="track-title action-input" type="text" value="${Utils.escape(lane.title)}" data-action="editLaneTitle" data-id="${lane.id}">
                <div class="restore-btn action-btn" role="button" tabindex="0" data-action="minLane" data-id="${lane.id}">${Utils.escape(lane.title)}</div>
            </div>
        `;
    });

    html += `<div class="add-col"><div class="add-btn action-btn" role="button" tabindex="0" data-action="addLane" title="Add Lane">+</div></div>`;

    state.habits.forEach((habit, idx) => {
        const bound = idx === 0 ? 'v-bound' : ''; 
        html += `
            <div class="habit-header-col ${bound}" title="Right-Click to delete habit">
                <div class="habit-header-input action-contenteditable" contenteditable="true" spellcheck="false" data-id="${habit.id}">${Utils.escape(habit.title)}</div>
                <div class="habit-stat" id="stat-${habit.id}"></div>
            </div>
        `;
    });

    html += `
        <div class="add-col">
            <div class="habit-action-col">
                <div class="add-btn action-btn" role="button" tabindex="0" data-action="addHabit" title="Add Habit">+</div>
                <div class="st-toggle">
                    <div class="action-btn ${state.settings.habitMode==='streak'?'active':''}" role="button" tabindex="0" data-action="setHabMode" data-val="streak">S</div>
                    <div class="action-btn ${state.settings.habitMode==='total'?'active':''}" role="button" tabindex="0" data-action="setHabMode" data-val="total">T</div>
                </div>
            </div>
        </div>
        <div class="diary-header-col v-bound"><div class="diary-title">Diary</div></div>
    `;
    DOM.header.innerHTML = html;
    this.habitStats();

    if (activeFocusSelector) { setTimeout(() => { const el = document.querySelector(activeFocusSelector); if(el) { el.focus(); try{ el.selectionStart = el.selectionEnd = el.value.length; }catch(e){} } }, 10); }
},

notesDrawerUI() {
    const lane = state.lanes.find(l => l.id === uiState.activeLaneNotes);
    DOM.notesLaneTitle.innerText = lane ? `${lane.title} Notes` : 'Notes';
    this.notesDrawerTabsOnly();
    const activeNote = state.notes.find(n => n.id === uiState.activeNoteId);
    if (activeNote) {
        DOM.noteEmptyState.style.display = 'none'; DOM.noteEditor.style.display = 'flex';
        DOM.noteTitleInput.value = activeNote.title; DOM.noteBodyInput.innerHTML = activeNote.content || '';
    } else { DOM.noteEmptyState.style.display = 'block'; DOM.noteEditor.style.display = 'none'; }
},

notesDrawerTabsOnly() {
    const laneNotes = state.notes.filter(n => n.laneId === uiState.activeLaneNotes);
    let tabsHtml = '';
    laneNotes.forEach(note => {
        const isActive = note.id === uiState.activeNoteId;
        tabsHtml += `
            <div class="note-tab action-btn ${isActive ? 'active' : ''}" role="button" tabindex="0" data-action="switchNote" data-id="${note.id}" title="${Utils.escape(note.title)}">
                ${Utils.escape(note.title) || 'Untitled'}
                <span class="del-note-btn action-btn" role="button" tabindex="0" data-action="deleteNote" data-id="${note.id}" title="Delete Note">×</span>
            </div>
        `;
    });

