input.new_string:
// ─── CONFIG ──────────────────────────────────────────────────────────────
// App-wide constants. Nothing in here changes while the app is running.
const Config = {
    // The badge types a task can cycle through. Each has a short letter label
    // shown on the coloured square in the UI. Pressing the badge rotates T→M→O→T.
    // ⚠️  BUG (V1): 'type-event' (E) is missing here — it exists in the latest
    //     version but was never added to V1. Fix: add { id:'type-event', label:'E' }.
    itemTypes: [{ id: 'type-task', label: 'T' }, { id: 'type-milestone', label: 'M' }, { id: 'type-outcome', label: 'O' }],

    // Eight accent colours that new lanes get assigned in order.
    // Users can also manually rotate a lane's colour by clicking its colour dot.
    PAL: ['#4F8EF7', '#8B5CF6', '#10B981', '#F59E0B', '#EF4444', '#06B6D4', '#EC4899', '#84CC16'],

    defaultTheme: 'dotted', // Starting paper style: 'dotted' or 'lined'

    // The name used to open the browser's IndexedDB database.
    // The version suffix (V10) is bumped whenever the data shape changes,
    // which tells the browser to run a schema upgrade and avoid reading stale data.
    dbName: 'SwimlaneDB_V10',

    // Key used to read/write backup data in localStorage (the simpler storage API).
    // Only used as a last resort if IndexedDB isn't available, or for legacy migration.
    fallbackKey: 'SwimlaneFallback_V10',

    // Cap on how many day-rows are kept in the DOM at once.
    // Once this is exceeded, rows at the opposite end are quietly removed.
    // Prevents the page from slowing down after hours of scrolling.
    maxRenderedDays: 120
};

