2	<html lang="en">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>Master Swimlane Journal</title>
7	    <link href="https://fonts.googleapis.com/css2?family=Caveat:wght@400;600;700&display=swap" rel="stylesheet">
8	    <script src="https://cdn.jsdelivr.net/npm/sortablejs@latest/Sortable.min.js"></script>
9	    <style>
10	        /* ================= BASE & METRONOME ================= */
11	        * { box-sizing: border-box; }
12	
13	        :root {
14	            --grid-size: 44px; 
15	            --left-margin: 176px; 
16	            
17	            --page-bg: #fdfbf7;
18	            --dot-color: #cbd5e1;
19	            --text-color: #1e293b;
20	            --today-bg: rgba(76, 175, 80, 0.08); 
