22	            --track-divider: rgba(0, 0, 0, 0.12); 
23	            
24	            --font-ui: 'Caveat', cursive; 
25	            --lc: #94a3b8; /* Default lane accent color */
26	        }
27	
28	        body.theme-dotted {
29	            --bg-pattern: radial-gradient(circle at 0 0, var(--dot-color) 1.5px, transparent 1.5px);
30	            --margin-line: var(--dot-color);
31	        }
32	        body.theme-lined {
33	            --bg-pattern: repeating-linear-gradient(transparent, transparent calc(var(--grid-size) - 1px), var(--dot-color) calc(var(--grid-size) - 1px), var(--dot-color) var(--grid-size));
34	            --margin-line: #ef4444; 
35	        }
36	
37	        body {
38	            background-color: var(--page-bg); background-image: var(--bg-pattern);
39	            background-size: var(--grid-size) var(--grid-size); background-position: -1px -1px; 
40	            background-attachment: local; font-family: var(--font-ui); color: var(--text-color);
41	            margin: 0; padding: 0; overflow-x: auto; scroll-behavior: smooth;
42	        }
