                <div class="dprog" id="dp-${dateStr}"><div class="dprog-fill"></div></div>
            </div>
            ${tracksHTML}
            <div class="empty-col"></div>
            ${habitCellsHTML}
            <div class="empty-col"></div>
            <div class="diary-cell v-bound"><textarea class="diary-input action-input" spellcheck="false" data-action="editDiary" data-date="${dateStr}">${Utils.escape(state.diary[dateStr] || '')}</textarea></div>
        `;
        dayMap.set(dateStr, dayBlock); return dayBlock;
    },

    trackContent(dateStr) {
        const dayBlock = dayMap.get(dateStr); if(!dayBlock) return;
        state.lanes.forEach(lane => {
            const track = dayBlock.querySelector(`.track.sl-${lane.id}`); if(!track) return;
            if (track.contains(document.activeElement)) return; 
            if (track._sortable) { track._sortable.destroy(); track._sortable = null; }
            track.innerHTML = '';
            state.items.filter(i => i.dateStr === dateStr && i.laneId === lane.id).forEach(itemData => {
                const itemEl = document.createElement('div');
                itemEl.className = `item sl-${lane.id} ${itemData.type} ${itemData.isDone ? 'is-done' : ''}`;
                itemEl.dataset.id = itemData.id;
                itemEl.innerHTML = Render.itemHTML(itemData); track.appendChild(itemEl);
            });
            DragDrop.initFor(track);
        });
    },

    itemHTML(itemData) {
        const typeConfig = Config.itemTypes.find(t => t.id === itemData.type) || Config.itemTypes[0];
        const isUrl = /^https?:\/\//i.test(itemData.text);
        const linkBtn = isUrl ? `<a href="${Utils.escape(itemData.text)}" target="_blank" class="url-btn action-btn" tabindex="-1">↗</a>` : '';
        return `
            <span class="type-badge action-btn" role="button" tabindex="0" title="Drag to move. Right-Click or Double-Tap to complete." data-action="cycleType">${typeConfig.label}</span>
            ${linkBtn}
            <input type="text" class="text-input action-input" value="${Utils.escape(itemData.text)}" autocomplete="off" spellcheck="false" data-action="editTask">
            <span class="countdown"></span>
            <div class="del-item-btn action-btn" role="button" tabindex="0" data-action="deleteItem" title="Delete">×</div>
        `;
    },

    habitStats() {
        const sysToday = Utils.todayStr;
        state.habits.forEach((habit) => {
            let count = 0, streakCount = 0;
            const allDates = Object.keys(state.habitChecks).filter(d => d <= sysToday).sort().reverse();
            for (const d of allDates) {
                if (state.habitChecks[d]?.[habit.id]) { count++; streakCount++; } else if(state.settings.habitMode === 'streak') break;
            }
            const display = document.getElementById(`stat-${habit.id}`);
            if(display) display.innerText = state.settings.habitMode === 'total' ? count : streakCount;
        });
    },

    updateDayToggles() {
        document.querySelectorAll('.day-block').forEach(block => {
            const toggle = block.querySelector('.day-toggle'); 
            let taskCount = 0;
            block.querySelectorAll('.track').forEach(track => { taskCount += track.children.length; });

            if(toggle) {
                toggle.style.display = taskCount > 1 ? 'block' : 'none';
                if (taskCount <= 1 && block.classList.contains('collapsed')) {
                    block.classList.remove('collapsed');
                    toggle.innerText = '▼';
                }
            }

            block.querySelectorAll('.type-outcome').forEach(outcome => {
                const d = Utils.getDiffDays(block.dataset.date);
                const span = outcome.querySelector('.countdown');
                if(span) span.innerText = d > 0 ? `(${d}d)` : d === 0 ? `(Today)` : `(Past)`;
            });
        });
    },

    updateProgress() {
        dayMap.forEach((block, dateStr) => {
            const prog = document.getElementById(`dp-${dateStr}`); if(!prog) return;
            const all = state.items.filter(i => i.dateStr === dateStr);
            if(!all.length) { prog.classList.remove('show'); return; }
            prog.classList.add('show');
            prog.querySelector('.dprog-fill').style.width = Math.round(all.filter(i => i.isDone).length / all.length * 100) + '%';
        });
    },

    applyScrollFilter() {
        if (!state.settings.showHorizon) return;
        const hh = DOM.header.getBoundingClientRect().height;
        document.querySelectorAll('.index-list li[data-date]').forEach(li => {
            const dayBlock = dayMap.get(li.dataset.date);
            if (!dayBlock) { li.style.display = state.settings.horizonMode === 'scroll' ? 'none' : 'flex'; return; }
            li.style.display = state.settings.horizonMode === 'all' ? 'flex' : (dayBlock.getBoundingClientRect().top > hh ? 'none' : 'flex');
        });
    }
};

