    processPending() {
        if (isVirtualizing) return;
        if (this.pendingForward) this.loadForward(30); else if (this.pendingBackward) this.loadBackward(30);
    },
    reset() {
        renderStartDate = Utils.today; if (!state.settings.showAchievements) { renderStartDate.setDate(renderStartDate.getDate() - 1); } else { renderStartDate.setDate(renderStartDate.getDate() - 30); }
        renderEndDate = new Date(renderStartDate.getTime()); renderEndDate.setDate(renderEndDate.getDate() - 1); 
        this.loadForward(60); 
    },
    seekToDate(targetDateStr) {
        const target = Utils.parseDate(targetDateStr);
        const existing = dayMap.get(targetDateStr);
        if (existing && document.body.contains(existing)) {
            existing.classList.remove('collapsed');
            const offset = DOM.header.offsetHeight + (state.settings.showHorizon ? DOM.horizon.offsetHeight : 0) + 10;
            setTimeout(() => window.scrollTo({top: existing.getBoundingClientRect().top + window.scrollY - offset, behavior: 'smooth'}), 10);
            return;
        }
        DOM.body.innerHTML = ''; dayMap.clear();
        renderStartDate = new Date(target.getTime()); renderStartDate.setDate(renderStartDate.getDate() - 15);
        renderEndDate = new Date(renderStartDate.getTime()); renderEndDate.setDate(renderEndDate.getDate() - 1); 
        this.loadForward(40);
        setTimeout(() => { 
            const el = dayMap.get(targetDateStr); 
            if(el) window.scrollTo({top: el.getBoundingClientRect().top + window.scrollY - (DOM.header.offsetHeight + (state.settings.showHorizon ? DOM.horizon.offsetHeight : 0) + 10), behavior: 'auto'}); 
        }, 50);
    },
    loadForward(count) {
        isVirtualizing = true; const frag = document.createDocumentFragment(); const datesAdded = [];
        for(let i=0; i<count; i++) { renderEndDate.setDate(renderEndDate.getDate() + 1); const dStr = Utils.toLocalISO(renderEndDate); frag.appendChild(Render.buildDayBlock(dStr)); datesAdded.push(dStr); }
        DOM.body.appendChild(frag); datesAdded.forEach(dStr => Render.trackContent(dStr)); Render.updateDayToggles(); Render.updateProgress();
        this.cleanupTop(); requestAnimationFrame(() => { requestAnimationFrame(() => { isVirtualizing = false; this.processPending(); }); });
    },
    loadBackward(count) {
        if (!state.settings.showAchievements && renderStartDate <= Utils.today) { this.pendingBackward = false; return; }
        isVirtualizing = true; const frag = document.createDocumentFragment(); const datesAdded = [];
        for(let i=0; i<count; i++) { renderStartDate.setDate(renderStartDate.getDate() - 1); datesAdded.unshift(Utils.toLocalISO(renderStartDate)); }
        datesAdded.forEach(dStr => frag.appendChild(Render.buildDayBlock(dStr)));
        const oldScroll = document.documentElement.scrollHeight; const oldTop = window.scrollY;
        DOM.body.insertBefore(frag, DOM.body.firstChild); datesAdded.forEach(dStr => Render.trackContent(dStr)); Render.updateDayToggles(); Render.updateProgress();
        window.scrollTo(0, oldTop + (document.documentElement.scrollHeight - oldScroll)); this.cleanupBottom();
        requestAnimationFrame(() => { requestAnimationFrame(() => { isVirtualizing = false; this.processPending(); }); });
    },
    cleanupTop() {
        const days = document.querySelectorAll('.day-block');
        if(days.length > Config.maxRenderedDays) {
            const toRemove = days.length - Config.maxRenderedDays; let removedHeight = 0;
            for(let i=0; i<toRemove; i++) { removedHeight += days[i].offsetHeight; days[i].querySelectorAll('.track').forEach(t => { if(t._sortable) t._sortable.destroy(); }); dayMap.delete(days[i].dataset.date); days[i].remove(); }
            renderStartDate = Utils.parseDate(days[toRemove].dataset.date); window.scrollBy(0, -removedHeight);
        }
    },
    cleanupBottom() {
        const days = document.querySelectorAll('.day-block');
        if(days.length > Config.maxRenderedDays) {
            const toRemove = days.length - Config.maxRenderedDays;
            for(let i=days.length-1; i >= days.length - toRemove; i--) { days[i].querySelectorAll('.track').forEach(t => { if(t._sortable) t._sortable.destroy(); }); dayMap.delete(days[i].dataset.date); days[i].remove(); }
            renderEndDate = Utils.parseDate(days[days.length-toRemove-1].dataset.date);
        }
    }
};

const DragDrop = {
    initFor(trackEl) {
        if (!trackEl._sortable) {
            trackEl._sortable = new Sortable(trackEl, {
                group: 'matrix', animation: 150, handle: '.type-badge', ghostClass: 'sortable-ghost',
                onStart: () => document.body.classList.add('is-dragging'),
                onEnd: function(evt) { 
                    document.body.classList.remove('is-dragging');
                    const id = evt.item.dataset.id; const toBlock = evt.to.closest('.day-block');
                    if (!state.items.find(i => i.id === id)) { EventBus.emit('itemsChanged'); return; }
                    if (toBlock && !evt.to.classList.contains('overdue-bin')) {
                        const domIds = Array.from(evt.to.children).map(child => child.dataset.id).filter(Boolean);
                        Actions.reorderTrack(id, toBlock.dataset.date, evt.to.dataset.laneId, domIds);
                    } else { EventBus.emit('itemsChanged'); }
                } 
            });
        }
    }
};

const Search = {
    init() {
        let searchTimer;
        DOM.searchInput.addEventListener('input', (e) => { clearTimeout(searchTimer); searchTimer = setTimeout(() => this.query(e.target.value), 200); });
        document.addEventListener('keydown', (e) => {
            if((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); this.toggle(); }
            if(e.key === 'Escape' && DOM.searchOverlay.classList.contains('is-open')) this.toggle(false);
        });
        DOM.searchOverlay.addEventListener('click', (e) => { if(e.target === DOM.searchOverlay) this.toggle(false); });
    },
    toggle(forceState) {
        const isOpen = forceState !== undefined ? forceState : !DOM.searchOverlay.classList.contains('is-open');
        DOM.searchOverlay.classList.toggle('is-open', isOpen);
        if(isOpen) { DOM.searchInput.value = ''; DOM.searchResults.innerHTML = ''; setTimeout(() => DOM.searchInput.focus(), 50); }
    },
    query(text) {
        DOM.searchResults.innerHTML = ''; if(text.trim().length < 2) return;
        const lower = text.toLowerCase(); const results = [];
        state.items.forEach(i => { if(i.text.toLowerCase().includes(lower)) results.push({ d: i.dateStr, t: i.text, type: 'Task' }); });
        Object.keys(state.diary).forEach(d => { if(state.diary[d].toLowerCase().includes(lower)) { let snippet = state.diary[d]; if (snippet.length > 80) snippet = snippet.substring(0, 80) + '...'; results.push({ d: d, t: snippet, type: 'Diary' }); } });
        results.sort((a,b) => b.d.localeCompare(a.d)).slice(0, 15).forEach(res => {
            const li = document.createElement('li'); li.className = 'search-item';
            li.innerHTML = `<span class="search-item-date">${res.d} &middot; ${res.type}</span><span class="search-item-text">${Utils.escape(res.t)}</span>`;
            li.addEventListener('click', () => { this.toggle(false); VirtualScroll.seekToDate(res.d); });
            DOM.searchResults.appendChild(li);
        });
    }
};

function BusWrap(evt, cb) { EventBus.on(evt, cb); }

