DOM.importUpload.addEventListener('change', (e) => {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
        try { const data = JSON.parse(ev.target.result); if (data && data.version) { Undo.snap('Import Backup'); Store.hydrate(data); Store.save(); location.reload(); } else alert("Invalid backup file."); } catch(err) { alert("Error reading file."); }
        e.target.value = ''; 
    }; reader.readAsText(file);
});

document.addEventListener('click', (e) => {
    // Make links in notes clickable
    if(e.target.tagName === 'A' && e.target.closest('#note-text-input')) {
        window.open(e.target.href, '_blank');
    }

    if(e.target.closest('#btn-link')) {
        e.preventDefault();
        const url = prompt('Enter link URL (including https://):', 'https://');
        if(url) { document.execCommand('createLink', false, url); DOM.noteBodyInput.dispatchEvent(new Event('input', {bubbles:true})); }
    }

    const btn = e.target.closest('.action-btn');
    if(btn) {
        const action = btn.dataset.action;
        if (e.type === 'click' && btn.getAttribute('role') === 'button') { e.target.blur(); } 

        if(action === 'toggleSettings') document.getElementById('settings-tray').classList.toggle('is-open');
        if(action === 'setTheme') Actions.toggleSetting('theme', btn.dataset.val);
        if(action === 'setHzMode') Actions.toggleSetting('horizonMode', btn.dataset.val);
        if(action === 'toggleAchievements') Actions.toggleAchievement();
        if(action === 'toggleHorizon') { if (!state.settings.showHorizon) VirtualScroll.seekToDate(Utils.todayStr); Actions.toggleHorizon(); }
        if(action === 'closeOnboarding') { DOM.onboarding.classList.remove('is-active'); localStorage.setItem('swimlane_onboarded', 'true'); }
        if(action === 'showOnboarding') DOM.onboarding.classList.add('is-active');

        if(action === 'exportData') Actions.exportData();
        if(action === 'importData') Actions.importData();

        if(action === 'scrollToToday') VirtualScroll.seekToDate(Utils.todayStr);
        if(action === 'seekToDate') VirtualScroll.seekToDate(btn.dataset.val);

        if(action === 'minLane') Actions.minLane(btn.dataset.id);
        if(action === 'delLane') Actions.delLane(btn.dataset.id);
        if(action === 'addLane') Actions.addLane();
        if(action === 'cycleColor') Actions.cycleLaneColor(btn.dataset.id);

        if(action === 'toggleHabit') { const nowChecked = !btn.classList.contains('is-checked'); btn.classList.toggle('is-checked', nowChecked); Actions.toggleHabit(btn.dataset.date, btn.dataset.id, nowChecked); }
        if(action === 'setHabMode') Actions.toggleSetting('habitMode', btn.dataset.val);
        if(action === 'addHabit') Actions.addHabit();

        if(action === 'cycleType') Actions.cycleType(btn.closest('.item').dataset.id);
        if(action === 'deleteItem') Actions.deleteItem(btn.closest('.item').dataset.id);
        if(action === 'toggleDay') { const b = btn.closest('.day-block'); b.classList.toggle('collapsed'); btn.innerText = b.classList.contains('collapsed') ? '▶' : '▼'; }

        if(action === 'openNotes') Actions.openNotes(btn.dataset.id);
        if(action === 'closeNotes') Actions.closeNotes();
        if(action === 'addNote') Actions.addNote();
        if(action === 'switchNote') Actions.switchNote(btn.dataset.id);
        if(action === 'deleteNote') { Actions.deleteNote(btn.dataset.id); e.stopPropagation(); return; }
        return;
    }

    if (!e.target.closest('.control-panel') && !e.target.closest('.search-modal') && !e.target.closest('.onboarding-modal') && !e.target.closest('.notes-drawer')) { const t = document.getElementById('settings-tray'); if(t) t.classList.remove('is-open'); }

    const track = e.target.closest('.track');
    if (track && !track.classList.contains('is-minimized') && !track.classList.contains('overdue-bin') && e.target === track) Actions.addItem(track.closest('.day-block').dataset.date, track.dataset.laneId);
});

