// INPUT: reads State.habits, State.habitChecks, State.settings.habitMode
// ALGO:  For each habit, calculates either the total count or the current streak.
//
//        "Total" mode: counts every day where the habit was checked, ever.
//
//        "Streak" mode: should count consecutive days ending today, but...
//        ⚠️  V1 BUG — this code iterates over Object.keys(habitChecks), which only
//        contains dates where at least one habit was interacted with. If the user
//        opened the app and checked habits on Mon, Wed, Fri but NOT Tue/Thu, those
//        gap days have no key, so the loop skips them silently — inflating the streak.
//        The fix (applied in Swimlane_App.html) walks consecutive calendar days
//        backward from today, stopping at the first unchecked day, regardless of
//        whether a key exists in habitChecks for that date.
//
// OUTPUT: the stat badge above each habit column header updated with a number
habitStats() {
    const sysToday = Utils.todayStr;
    state.habits.forEach((habit) => {
        let count = 0, streakCount = 0;
        const allDates = Object.keys(state.habitChecks).filter(d => d <= sysToday).sort().reverse();
        for (const d of allDates) {
            if (state.habitChecks[d]?.[habit.id]) { count++; streakCount++; } else if(state.settings.habitMode === 'streak') break;
        }
