habitStats() {
    const sysToday = Utils.todayStr;
    state.habits.forEach((habit) => {
        let count = 0, streakCount = 0;
        const allDates = Object.keys(state.habitChecks).filter(d => d <= sysToday).sort().reverse();
        for (const d of allDates) {
            if (state.habitChecks[d]?.[habit.id]) { count++; streakCount++; } else if(state.settings.habitMode === 'streak') break;
        }
        const display = document.getElementById(`stat-${habit.id}`);
        if(display) display.innerText = state.settings.habitMode === 'total' ? count : streakCount;
    });
},

input.new_string:
habitStats() {
    const sysToday = Utils.todayStr;
    state.habits.forEach((habit) => {
        // Total count: sum every day where the habit was checked (any order).
        let count = 0;
        Object.keys(state.habitChecks).forEach(d => { if (d <= sysToday && state.habitChecks[d]?.[habit.id]) count++; });

        // Streak count: walk consecutive calendar days backward from today.
        // Stops at the first day that is NOT checked, even if habitChecks has no
        // key for that date (that was the V1 bug — keys only exist for days where
        // at least one habit was touched, so the old loop skipped gap days).
        let streakCount = 0;
        const checkDate = new Date(Utils.today);
        while (true) {
            const dateStr = Utils.toLocalISO(checkDate);
            if (state.habitChecks[dateStr]?.[habit.id]) {
                streakCount++;
            } else {
                break;
            }
            checkDate.setDate(checkDate.getDate() - 1);
        }

        const display = document.getElementById(`stat-${habit.id}`);
        if(display) display.innerText = state.settings.habitMode === 'total' ? count : streakCount;
    });
},

